import { Stack, Link, Button, TextField } from "@mui/material";

const Login = () => {
  return (
    <>
      <Stack spacing={2}>
        <Stack spacing={2}>
            <TextField label="Mail Address" placeholder="Enter your mail address" />
            <TextField label="Password" placeholder="Enter your password" />
            <Button>Login</Button>
        </Stack>
        <Link href="/signup">Don't have an account yet?</Link>
      </Stack>
    </>
  );
};

export default Login;
